import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import api from "../../api/axios";
import { updateDoc } from "../../api/documentApi";

export default function EditDocument() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [vehicles, setVehicles] = useState([]);
  const [users, setUsers] = useState([]); // holders
  const [form, setForm] = useState(null);
  const [loading, setLoading] = useState(true);

  // ✅ adjust if your vehicle schema uses different field name
  const getVehicleNumber = (v) =>
    v?.vehicleNumber || v?.vehicle_number || v?.registrationNo || v?.regNo || "";

  useEffect(() => {
    const load = async () => {
      try {
        setLoading(true);

        const [docRes, vehicleRes, userRes] = await Promise.all([
          api.get(`/documents/${id}`),
          api.get("/vehicles"),
          api.get("/users"), // ⚠️ MUST exist in backend (admin router). If not, read note below.
        ]);

        const d = docRes.data;

        setForm({
          title: d.title || "",
          docType: d.docType || "RC_BOOK",
          referenceNo: d.referenceNo || "",
          vehicle: d.vehicle?._id || "",
          status: d.status || "AVAILABLE",
          location: d.location || "",
          holder: d.holder?._id || "",
          notes: d.notes || "",
        });

        setVehicles(vehicleRes.data || []);
        setUsers((userRes.data || []).filter((u) => !u.isDeleted)); // only active
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load document");
        navigate("/documents");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [id, navigate]);

  const submit = async (e) => {
    e.preventDefault();

    try {
      await updateDoc(id, {
        title: form.title,
        docType: form.docType,
        referenceNo: form.referenceNo,
        status: form.status,
        location: form.location,
        notes: form.notes,

        // ✅ if empty, remove from payload
        vehicle: form.vehicle || undefined,
        holder: form.holder || undefined,
      });

      alert("Document updated!");
      navigate("/documents");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  if (loading || !form) return <p style={{ padding: 20 }}>Loading...</p>;

  return (
    <div style={{ padding: 20, maxWidth: 560 }}>
      <h2>Edit Physical Document</h2>

      <form onSubmit={submit}>
        <label>Title</label><br />
        <input
          value={form.title}
          onChange={(e) => setForm({ ...form, title: e.target.value })}
          style={{ width: "100%", padding: 10 }}
          required
        />

        <br /><br />

        <label>Type</label><br />
        <select
          value={form.docType}
          onChange={(e) => setForm({ ...form, docType: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="RC_BOOK">RC Book</option>
          <option value="INSURANCE">Insurance</option>
          <option value="TRANSFER_FORM">Transfer Form</option>
          <option value="EMISSION">Emission</option>
          <option value="SERVICE_BOOK">Service Book</option>
          <option value="OTHER">Other</option>
        </select>

        <br /><br />

        <label>Reference No (optional)</label><br />
        <input
          value={form.referenceNo}
          onChange={(e) => setForm({ ...form, referenceNo: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <label>Vehicle</label><br />
        <select
          value={form.vehicle}
          onChange={(e) => setForm({ ...form, vehicle: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="">-- none --</option>
          {vehicles.map((v) => {
            const vNum = getVehicleNumber(v);
            return (
              <option key={v._id} value={v._id}>
                {v.brand} {v.model || v.type || ""} ({v.year}){vNum ? ` - ${vNum}` : ""}
              </option>
            );
          })}
        </select>

        <br /><br />

        <label>Holder</label><br />
        <select
          value={form.holder}
          onChange={(e) => setForm({ ...form, holder: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="">-- none --</option>
          {users.map((u) => (
            <option key={u._id} value={u._id}>
              {u.name} ({u.role})
            </option>
          ))}
        </select>

        <br /><br />

        <label>Status</label><br />
        <select
          value={form.status}
          onChange={(e) => setForm({ ...form, status: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="AVAILABLE">AVAILABLE</option>
          <option value="IN_USE">IN_USE</option>
          <option value="MISSING">MISSING</option>
          <option value="ARCHIVED">ARCHIVED</option>
        </select>

        <br /><br />

        <label>Location</label><br />
        <input
          value={form.location}
          onChange={(e) => setForm({ ...form, location: e.target.value })}
          style={{ width: "100%", padding: 10 }}
          required
          placeholder="e.g., Office Cabinet A"
        />

        <br /><br />

        <label>Note</label><br />
        <textarea
          value={form.notes}
          onChange={(e) => setForm({ ...form, notes: e.target.value })}
          rows={3}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <button style={{ padding: "10px 14px" }}>Save Changes</button>
      </form>
    </div>
  );
}
